import{_ as a,a as i,b as t}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as l,o,c as n,a2 as r}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Аутентификация и управление устройствами входа","description":"","frontmatter":{},"headers":[],"relativePath":"ru-RU/Safety/authentication-and-login-devices.md","filePath":"ru-RU/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),c={name:"ru-RU/Safety/authentication-and-login-devices.md"};function d(p,e,s,h,u,m){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="аутентификация-и-управление-устроиствами-входа" tabindex="-1">Аутентификация и управление устройствами входа <a class="header-anchor" href="#аутентификация-и-управление-устроиствами-входа" aria-label="Permalink to &quot;Аутентификация и управление устройствами входа&quot;">​</a></h1><p><code>Authentication Management</code> и <code>Login Device Management</code> защищают админ-панель ImgBed, публичную страницу загрузки и WebDAV-доступ.</p><p>На этой странице можно настроить учетные данные доступа, просмотреть устройства, которые входили в систему, и при необходимости отозвать старые сессии.</p><h2 id="где-это-настраивается" tabindex="-1">Где это настраивается <a class="header-anchor" href="#где-это-настраивается" aria-label="Permalink to &quot;Где это настраивается&quot;">​</a></h2><p>Откройте админ-панель и перейдите в:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings</span></span></code></pre></div><p>На странице есть две основные области:</p><ul><li>Authentication Management</li><li>Login Device Management</li></ul><p><img src="'+a+'" alt="Управление аутентификацией" loading="lazy"></p><h2 id="для-чего-нужен-authentication-management" tabindex="-1">Для чего нужен Authentication Management <a class="header-anchor" href="#для-чего-нужен-authentication-management" aria-label="Permalink to &quot;Для чего нужен Authentication Management&quot;">​</a></h2><p>Authentication Management хранит учетные данные доступа.</p><p>Есть два типа:</p><ul><li>аутентификация пользовательской стороны;</li><li>аутентификация админ-стороны.</li></ul><h2 id="аутентификация-пользовательскои-стороны" tabindex="-1">Аутентификация пользовательской стороны <a class="header-anchor" href="#аутентификация-пользовательскои-стороны" aria-label="Permalink to &quot;Аутентификация пользовательской стороны&quot;">​</a></h2><p>Аутентификация пользовательской стороны — это пароль для загрузки.</p><p>После установки пароля обычные посетители должны ввести его перед использованием страницы загрузки. Это полезно, если вы не хотите открывать публичную страницу загрузки для всех.</p><p><img src="'+i+'" alt="Страница входа пользователя" loading="lazy"></p><h3 id="настроика-пароля-загрузки" tabindex="-1">Настройка пароля загрузки <a class="header-anchor" href="#настроика-пароля-загрузки" aria-label="Permalink to &quot;Настройка пароля загрузки&quot;">​</a></h3><p>Когда пароль загрузки настроен:</p><ul><li>посетители должны ввести пароль перед использованием страницы загрузки;</li><li>загрузка доступна только после принятия пароля;</li><li>если включены сессии устройств пользовательской стороны, ImgBed записывает это устройство.</li></ul><p>Изменение пароля загрузки делает старые пользовательские сессии недействительными. Посетителям нужно будет ввести новый пароль.</p><h2 id="аутентификация-админ-стороны" tabindex="-1">Аутентификация админ-стороны <a class="header-anchor" href="#аутентификация-админ-стороны" aria-label="Permalink to &quot;Аутентификация админ-стороны&quot;">​</a></h2><p>Аутентификация админ-стороны использует имя администратора и пароль.</p><p>Она защищает админ-панель. Для production-сайта ее стоит всегда настраивать.</p><p><img src="'+t+'" alt="Страница входа администратора" loading="lazy"></p><h3 id="настроика-учетных-данных-администратора" tabindex="-1">Настройка учетных данных администратора <a class="header-anchor" href="#настроика-учетных-данных-администратора" aria-label="Permalink to &quot;Настройка учетных данных администратора&quot;">​</a></h3><p>Когда имя администратора и пароль настроены:</p><ul><li>открытие админ-панели требует входа;</li><li>успешный вход создает запись admin device;</li><li>в Login Device Management можно просматривать, чистить или принудительно выводить устройства офлайн.</li></ul><p>Изменение имени администратора или пароля делает старые admin sessions недействительными. Нужно будет войти снова.</p><h2 id="для-чего-нужен-login-device-management" tabindex="-1">Для чего нужен Login Device Management <a class="header-anchor" href="#для-чего-нужен-login-device-management" aria-label="Permalink to &quot;Для чего нужен Login Device Management&quot;">​</a></h2><p>Login Device Management показывает устройства, которые входили в систему.</p><p>Он помогает проверить:</p><ul><li>какие устройства открывали админ-панель;</li><li>какие устройства открывали пользовательскую страницу загрузки;</li><li>какие WebDAV-клиенты подключались;</li><li>действительна ли сессия устройства;</li><li>нужно ли принудительно вывести старые устройства офлайн.</li></ul><p>На странице есть три вкладки:</p><ul><li>Admin</li><li>User</li><li>WebDAV</li></ul><h2 id="глобальная-безопасность-cookie" tabindex="-1">Глобальная безопасность cookie <a class="header-anchor" href="#глобальная-безопасность-cookie" aria-label="Permalink to &quot;Глобальная безопасность cookie&quot;">​</a></h2><p>В верхней части Login Device Management можно настроить глобальное поведение cookie.</p><h3 id="user-cookie-lifetime" tabindex="-1">User Cookie Lifetime <a class="header-anchor" href="#user-cookie-lifetime" aria-label="Permalink to &quot;User Cookie Lifetime&quot;">​</a></h3><p>Определяет, сколько дней пользовательский вход может оставаться активным.</p><p>Например, если установить 14 дней, посетителям обычно не нужно повторно вводить пароль загрузки в течение 14 дней.</p><h3 id="admin-cookie-lifetime" tabindex="-1">Admin Cookie Lifetime <a class="header-anchor" href="#admin-cookie-lifetime" aria-label="Permalink to &quot;Admin Cookie Lifetime&quot;">​</a></h3><p>Определяет, сколько дней вход администратора может оставаться активным.</p><p>Например, если установить 14 дней, администраторам обычно не нужно повторно входить в течение 14 дней.</p><h3 id="secure-mode" tabindex="-1">Secure Mode <a class="header-anchor" href="#secure-mode" aria-label="Permalink to &quot;Secure Mode&quot;">​</a></h3><p>Когда Secure mode включен, браузеры отправляют login cookies только через HTTPS.</p><p>Включайте его для production-сайтов с HTTPS. Не включайте для локального HTTP-тестирования, иначе можно получить поведение вроде &quot;вход успешен, но после обновления страницы меня выбрасывает&quot;.</p><h2 id="устроиства-входа-администратора" tabindex="-1">Устройства входа администратора <a class="header-anchor" href="#устроиства-входа-администратора" aria-label="Permalink to &quot;Устройства входа администратора&quot;">​</a></h2><p>Вкладка Admin показывает устройства, которые входили в админ-панель.</p><p>Записи устройств появляются только после настройки admin credentials и входа в админ-панель через форму логина.</p><p>Карточка устройства может показывать:</p><ul><li>информацию об устройстве и браузере;</li><li>IP первого входа;</li><li>IP последней активности;</li><li>время входа;</li><li>время последней активности;</li><li>время истечения сессии;</li><li>текущий статус.</li></ul><p>Если видите незнакомое устройство, используйте <code>Force Offline</code>, чтобы сделать его сессию недействительной.</p><h2 id="очистка-старых-устроиств" tabindex="-1">Очистка старых устройств <a class="header-anchor" href="#очистка-старых-устроиств" aria-label="Permalink to &quot;Очистка старых устройств&quot;">​</a></h2><p><code>Clean Up Old Devices</code> массово удаляет старые записи входа в текущей вкладке.</p><p>Используйте это, если подозреваете, что старые сессии на других устройствах все еще могут быть активны.</p><h2 id="force-offline" tabindex="-1">Force Offline <a class="header-anchor" href="#force-offline" aria-label="Permalink to &quot;Force Offline&quot;">​</a></h2><p><code>Force Offline</code> делает недействительной одну сессию устройства.</p><p>После принудительного вывода устройства офлайн:</p><ul><li>admin devices должны войти снова;</li><li>устройства пользовательской стороны должны снова ввести пароль загрузки;</li><li>WebDAV-клиенты должны пройти аутентификацию еще раз.</li></ul><p>Просроченные или недействительные устройства также можно удалять.</p><h2 id="выход-с-текущего-устроиства" tabindex="-1">Выход с текущего устройства <a class="header-anchor" href="#выход-с-текущего-устроиства" aria-label="Permalink to &quot;Выход с текущего устройства&quot;">​</a></h2><p>Карточка текущего устройства помечена как <code>Current Device</code>.</p><p>После выхода с текущего устройства:</p><ul><li>текущая admin session завершается;</li><li>текущая user-side session завершается.</li></ul><p>Чтобы продолжить пользоваться соответствующей областью, нужно войти снова.</p>',65)])])}const k=l(c,[["render",d]]);export{b as __pageData,k as default};
